from google.adk.sessions import InMemorySessionService

session_service = InMemorySessionService()

async def chat_with_agent(user_id: str, session_id: str, message: str):
    session = await session_service.get_session(
        app_name="my_app", user_id=user_id, session_id=session_id
    )
    if session is None:
        session = await session_service.create_session(
            app_name="my_app", user_id=user_id
        )

    user_message = genai_types.Content(
        role="user", parts=[genai_types.Part(text=message)]
    )
    final_text = ""
    async for event in runner.run_async(
        user_id=user_id, session_id=session.id, new_message=user_message
    ):
        if event.is_final_response() and event.content:
            final_text = event.content.parts[0].text
    return final_text, session.id

from google.adk.agents import LlmAgent, CallbackContext
from google.adk.models import LlmResponse

def log_model_response(callback_context: CallbackContext, llm_response: LlmResponse):
    """Called after every LLM response; return None to pass through."""
    print(f"[trace] model returned {len(llm_response.content.parts)} part(s)")
    return None   # pass through unchanged

def safety_filter(callback_context: CallbackContext, llm_response: LlmResponse):
    """Block responses containing a forbidden word."""
    if llm_response.content:
        for part in llm_response.content.parts:
            if "forbidden_word" in (part.text or "").lower():
                from google.adk.models import LlmResponse
                import google.generativeai.types as gtypes
                safe = gtypes.Content(role="model", parts=[gtypes.Part(text="I cannot answer that.")])
                return LlmResponse(content=safe)
    return None

agent = LlmAgent(
    name="safe_agent",
    model="gemini-2.0-flash-exp",
    instruction="You are a helpful assistant.",
    after_model_callback=log_model_response,
)

async for event in runner.run_async(...):
    if event.is_final_response():
        print("Final:", event.content.parts[0].text)
    elif event.get_function_calls():
        for call in event.get_function_calls():
            print(f"Tool call: {call.name}({call.args})")
    elif event.get_function_responses():
        for resp in event.get_function_responses():
            print(f"Tool result: {resp.name} = {resp.response}")
